#include <bits/stdc++.h>
using namespace std;
struct dao
{
    int begin,end;
    double x,y;
};
dao a[2005];
bool fun(dao x,dao y)
{
    if(x.end<y.end)
    {
        return true;
    }
    else if(x.end==y.end&&x.begin>y.begin)
    {
        return true;
    }
    return false;
}
int main()
{
    int n;
    double d;
    cin>>n>>d;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i].x>>a[i].y;
        if(a[i].y>d)
        {
            cout<<-1;
            return 0;
        }
        a[i].begin=a[i].x-sqrt(d*d-a[i].y*a[i].y);
        a[i].end=a[i].x+sqrt(d*d-a[i].y*a[i].y);
    }
    sort(a+1,a+1+n,fun);
    int ans=1;
    int beginn=a[1].begin,endd=a[1].end;
    for(int i=2;i<=n;i++)
    {
        if(a[i].begin<endd)
        {
            beginn=a[i].begin;
        }
        else
        {
            ans++;
            beginn=a[i].begin;
            endd=a[i].end;
        }
    }
    cout<<ans;
    return 0;
}
